// CONFIGURATION: Nom du dossier cible (modifiez ici)
const DOSSIER_CIBLE = 'template rapport';

const items = $input.all();

// Si aucun item
if (!items || items.length === 0 || !items[0].json || Object.keys(items[0].json).length === 0) {
  return [{
    json: {
      success: false,
      timestamp: new Date().toISOString(),
      message: "Aucun fichier trouvé dans Google Drive",
      dossierRecherche: DOSSIER_CIBLE,
      dossiersDisponibles: [],
      contenu: []
    }
  }];
}

// Construire un index des dossiers
const dossiersMap = {};
const tousLesDossiers = [];
let dossierCible = null;

for (const item of items) {
  const data = item.json;
  if (!data || !data.id) continue;

  if (data.mimeType === 'application/vnd.google-apps.folder') {
    dossiersMap[data.id] = { id: data.id, nom: data.name || 'Sans nom' };
    tousLesDossiers.push(data.name);

    const nomLower = (data.name || '').toLowerCase().trim();
    const cibleLower = DOSSIER_CIBLE.toLowerCase().trim();

    if (nomLower === cibleLower || 
        nomLower === cibleLower.replace(/ /g, '_') ||
        nomLower === cibleLower.replace(/ /g, '')) {
      dossierCible = { id: data.id, nom: data.name };
    }
  }
}

// Si dossier cible non trouvé
if (!dossierCible) {
  return [{
    json: {
      success: false,
      timestamp: new Date().toISOString(),
      message: `Dossier '${DOSSIER_CIBLE}' non trouvé`,
      dossierRecherche: DOSSIER_CIBLE,
      dossiersDisponibles: tousLesDossiers.slice(0, 30),
      contenu: []
    }
  }];
}

// Construire la liste de tous les éléments avec leur dossier parent
// Note: Sans le champ 'parents' de l'API, on ne peut pas filtrer directement
// On retourne donc tous les éléments avec l'info du dossier cible trouvé

const contenu = [];
for (const item of items) {
  const data = item.json;
  if (!data || !data.id) continue;

  contenu.push({
    fichier_id: data.id,
    fichier_nom: data.name || 'Sans nom',
    fichier_type: data.mimeType === 'application/vnd.google-apps.folder' ? 'dossier' : 'fichier',
    fichier_mimeType: data.mimeType || 'unknown',
    dossier_parent_id: dossierCible.id,
    dossier_parent_nom: dossierCible.nom
  });
}

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    dossierCible: dossierCible,
    statistiques: {
      totalElements: contenu.length,
      sousDossiers: contenu.filter(e => e.fichier_type === 'dossier').length,
      fichiers: contenu.filter(e => e.fichier_type === 'fichier').length
    },
    contenu: contenu
  }
}];
